          , BOOK_ISBN
          , BOOK_PUBL
          , BOOK_TITL
          , BOOK_DESC
          , PUBL_DATE
) VALUES (  #{bookNumb}
          , #{bookAthr}
          , #{bookCvim}
          , #{bookIsbn}
          , #{bookPubl}
          , #{bookTitl}
          , #{bookDesc}
          , #{publDate}
)
